import { Pool } from 'pg';
import { pool } from '../../shared/db/connection';
import { Note, CreateNoteDto } from './notes.model';
import { AppError } from '../../shared/types';

export interface INotesRepository {
  findAll(): Promise<Note[]>;
  findById(id: string): Promise<Note | null>;
  create(dto: CreateNoteDto): Promise<Note>;
}

export class PostgresNotesRepository implements INotesRepository {
  private pool: Pool;

  constructor(pool: Pool) {
    this.pool = pool;
  }

  async findAll(): Promise<Note[]> {
    try {
      const result = await this.pool.query(
        'SELECT id, title, body, status, created_at, updated_at FROM notes WHERE status = $1 ORDER BY created_at DESC',
        ['ACTIVE']
      );
      return result.rows.map(this.mapRowToNote);
    } catch (error) {
      throw new AppError('Failed to fetch notes', 500);
    }
  }

  async findById(id: string): Promise<Note | null> {
    try {
      const result = await this.pool.query(
        'SELECT id, title, body, status, created_at, updated_at FROM notes WHERE id = $1 AND status = $2',
        [id, 'ACTIVE']
      );
      return result.rows.length ? this.mapRowToNote(result.rows[0]) : null;
    } catch (error) {
      throw new AppError('Failed to fetch note', 500);
    }
  }

  async create(dto: CreateNoteDto): Promise<Note> {
    try {
      const result = await this.pool.query(
        'INSERT INTO notes (title, body) VALUES ($1, $2) RETURNING id, title, body, status, created_at, updated_at',
        [dto.title, dto.body]
      );
      return this.mapRowToNote(result.rows[0]);
    } catch (error) {
      throw new AppError('Failed to create note', 500);
    }
  }

  private mapRowToNote(row: any): Note {
    return {
      id: row.id,
      title: row.title,
      body: row.body,
      status: row.status as Note['status'],
      createdAt: row.created_at,
      updatedAt: row.updated_at
    };
  }
}","File: tests/unit/modules/notes/notes.repository.test.ts
import { PostgresNotesRepository } from '../../../src/modules/notes/notes.repository';
import { Note, NoteStatus } from '../../../src/modules/notes/notes.model';
import { Pool } from 'pg';

// Jest mock for pg Pool
jest.mock('pg', () => {
  const mPool = {
    query: jest.fn()
  };
  return { Pool: jest.fn(() => mPool) };
});

describe('PostgresNotesRepository', () => {
  let repository: PostgresNotesRepository;
  let mockPool: any;

  beforeEach(() => {
    mockPool = new Pool();
    repository = new PostgresNotesRepository(mockPool);
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  describe('findAll', () => {
    it('should return only active notes ordered by created_at DESC', async () => {
      const mockRows = [
        { id: '1', title: 'Note 1', body: 'Body 1', status: 'ACTIVE', created_at: new Date(), updated_at: new Date() }
      ];
      mockPool.query.mockResolvedValueOnce({ rows: mockRows });

      const notes = await repository.findAll();

      expect(mockPool.query).toHaveBeenCalledWith(
        'SELECT id, title, body, status, created_at, updated_at FROM notes WHERE status = $1 ORDER BY created_at DESC',
        ['ACTIVE']
      );
      expect(notes).toHaveLength(1);
      expect(notes[0].status).toBe(NoteStatus.ACTIVE);
    });

    it('should throw AppError on query failure', async () => {
      mockPool.query.mockRejectedValueOnce(new Error('DB error'));
      await expect(repository.findAll()).rejects.toThrow('Failed to fetch notes');
    });
  });

  describe('findById', () => {
    it('should return note if active', async () => {
      const mockRow = { id: '1', title: 'Note', body: 'Body', status: 'ACTIVE', created_at: new Date(), updated_at: new Date() };
      mockPool.query.mockResolvedValueOnce({ rows: [mockRow] });

      const note = await repository.findById('1');

      expect(mockPool.query).toHaveBeenCalledWith(
        'SELECT id, title, body, status, created_at, updated_at FROM notes WHERE id = $1 AND status = $2',
        ['1', 'ACTIVE']
      );
      expect(note).not.toBeNull();
      expect(note!.status).toBe(NoteStatus.ACTIVE);
    });

    it('should return null if note not found or not active', async () => {
      mockPool.query.mockResolvedValueOnce({ rows: [] });
      const note = await repository.findById('nonexistent');
      expect(note).toBeNull();
    });

    it('should throw AppError on query failure', async () => {
      mockPool.query.mockRejectedValueOnce(new Error('DB error'));
      await expect(repository.findById('1')).rejects.toThrow('Failed to fetch note');
    });
  });

  describe('create', () => {
    it('should insert a note and return it with ACTIVE status', async () => {
      const dto = { title: 'New Note', body: 'New Body' };
      const mockRow = { id: '2', title: 'New Note', body: 'New Body', status: 'ACTIVE', created_at: new Date(), updated_at: new Date() };
      mockPool.query.mockResolvedValueOnce({ rows: [mockRow] });

      const note = await repository.create(dto);

      expect(mockPool.query).toHaveBeenCalledWith(
        'INSERT INTO notes (title, body) VALUES ($1, $2) RETURNING id, title, body, status, created_at, updated_at',
        ['New Note', 'New Body']
      );
      expect(note.status).toBe(NoteStatus.ACTIVE);
      expect(note.title).toBe('New Note');
    });

    it('should throw AppError on query failure', async () => {
      mockPool.query.mockRejectedValueOnce(new Error('DB error'));
      await expect(repository.create({ title: 'x', body: 'y' })).rejects.toThrow('Failed to create note');
    });
  });
